package com.project.scripts;

import com.project.entity.Category;
import com.project.entity.Color;
import com.project.entity.Product;
import com.project.entity.Size;
import com.project.entity.Tag;
import com.project.repository.CategoryRepository;
import com.project.repository.ColorRepository;
import com.project.repository.ProductRepository;
import com.project.repository.SizeRepository;
import com.project.repository.TagRepository;
import org.springframework.boot.CommandLineRunner;
import org.springframework.stereotype.Component;
import org.springframework.transaction.annotation.Transactional;

import java.util.ArrayList;
import java.util.Base64;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Random;

@Component
public class ProductSeeder implements CommandLineRunner {

    private static final long TARGET_PRODUCT_COUNT = 100;
    private static final String PLACEHOLDER_IMAGE_BASE64 =
            "";

    private final ProductRepository productRepository;
    private final CategoryRepository categoryRepository;
    private final SizeRepository sizeRepository;
    private final ColorRepository colorRepository;
    private final TagRepository tagRepository;

    public ProductSeeder(
            ProductRepository productRepository,
            CategoryRepository categoryRepository,
            SizeRepository sizeRepository,
            ColorRepository colorRepository,
            TagRepository tagRepository
    ) {
        this.productRepository = productRepository;
        this.categoryRepository = categoryRepository;
        this.sizeRepository = sizeRepository;
        this.colorRepository = colorRepository;
        this.tagRepository = tagRepository;
    }

    @Override
    @Transactional
    public void run(String... args) {
        long existingCount = productRepository.count();
        if (existingCount >= TARGET_PRODUCT_COUNT) {
            return;
        }

        Map<String, Integer> categoryTargets = new LinkedHashMap<>();
        categoryTargets.put("Footwear", 30);
        categoryTargets.put("Apparel", 24);
        categoryTargets.put("Accessories", 18);
        categoryTargets.put("Training", 16);
        categoryTargets.put("Equipment", 12);

        List<Size> standardSizes = ensureSizes(List.of("XS", "S", "M", "L", "XL", "XXL"));
        List<Size> shoeSizes = ensureSizes(List.of("7", "8", "9", "10", "11", "12"));
        List<Color> neutralColors = ensureColors(List.of("Black", "White", "Grey", "Navy", "Red", "Olive"));
        List<Color> accentColors = ensureColors(List.of("Blue", "Green", "Orange", "Gold", "Purple", "Silver"));
        List<Tag> commonTags = ensureTags(List.of("performance", "premium", "training", "sport", "top-notch"));
        byte[] placeholderImage = Base64.getDecoder().decode(PLACEHOLDER_IMAGE_BASE64);

        List<Product> productsToCreate = new ArrayList<>();
        int globalIndex = (int) existingCount + 1;
        Random random = new Random(42);

        for (Map.Entry<String, Integer> categoryTarget : categoryTargets.entrySet()) {
            Category category = ensureCategory(categoryTarget.getKey());
            int existingForCategory = category.getProducts() == null ? 0 : category.getProducts().size();
            int missingForCategory = Math.max(0, categoryTarget.getValue() - existingForCategory);

            for (int categoryIndex = 0; categoryIndex < missingForCategory; categoryIndex++) {
                Product product = new Product();
                product.setName(category.getName() + " Product " + globalIndex);
                product.setCategory(category);
                product.setQuantity(5 + random.nextInt(96));

                double basePrice = switch (category.getName()) {
                    case "Footwear" -> 120.0;
                    case "Apparel" -> 45.0;
                    case "Accessories" -> 25.0;
                    case "Training" -> 60.0;
                    default -> 80.0;
                };

                double price = basePrice + (random.nextInt(18) * 5);
                product.setPrice(price);
                product.setOriginalPrice(random.nextBoolean() ? price + 20 : null);
                product.setDescription(buildDescription(category.getName(), globalIndex));
                product.setRating(3.8 + (random.nextInt(12) / 10.0));
                product.setReviews(20 + random.nextInt(480));
                product.setSizes(selectSizes(category.getName(), standardSizes, shoeSizes, globalIndex));
                product.setColors(selectColors(category.getName(), neutralColors, accentColors, globalIndex));
                product.setTags(selectTags(commonTags, category.getName(), globalIndex));
                product.setNew(globalIndex % 4 == 0);
                product.setLimited(globalIndex % 9 == 0);
                product.setBestseller(globalIndex % 5 == 0);
                product.setImageBlob(placeholderImage);

                productsToCreate.add(product);
                globalIndex++;

                if (existingCount + productsToCreate.size() >= TARGET_PRODUCT_COUNT) {
                    productRepository.saveAll(productsToCreate);
                    return;
                }
            }
        }

        if (!productsToCreate.isEmpty()) {
            productRepository.saveAll(productsToCreate);
        }
    }

    private Category ensureCategory(String name) {
        return categoryRepository.findByName(name)
                .orElseGet(() -> categoryRepository.save(new Category(name)));
    }

    private List<Size> ensureSizes(List<String> values) {
        List<Size> sizes = new ArrayList<>();
        for (String value : values) {
            sizes.add(sizeRepository.findByValue(value)
                    .orElseGet(() -> sizeRepository.save(new Size(value))));
        }
        return sizes;
    }

    private List<Color> ensureColors(List<String> values) {
        List<Color> colors = new ArrayList<>();
        for (String value : values) {
            colors.add(colorRepository.findByValue(value)
                    .orElseGet(() -> colorRepository.save(new Color(value))));
        }
        return colors;
    }

    private List<Tag> ensureTags(List<String> values) {
        List<Tag> tags = new ArrayList<>();
        for (String value : values) {
            tags.add(tagRepository.findByName(value)
                    .orElseGet(() -> tagRepository.save(new Tag(value))));
        }
        return tags;
    }

    private String buildDescription(String categoryName, int index) {
        return categoryName + " item " + index + " built for daily performance, reliable comfort, and clean Top Notch store presentation.";
    }

    private List<Size> selectSizes(String categoryName, List<Size> standardSizes, List<Size> shoeSizes, int index) {
        if ("Footwear".equals(categoryName)) {
            return new ArrayList<>(shoeSizes.subList(0, 3 + (index % 4)));
        }
        if ("Accessories".equals(categoryName) || "Equipment".equals(categoryName)) {
            return List.of();
        }
        return new ArrayList<>(standardSizes.subList(0, 3 + (index % 3)));
    }

    private List<Color> selectColors(String categoryName, List<Color> neutralColors, List<Color> accentColors, int index) {
        List<Color> palette = new ArrayList<>();
        palette.add(neutralColors.get(index % neutralColors.size()));
        palette.add(neutralColors.get((index + 2) % neutralColors.size()));
        if (!"Equipment".equals(categoryName)) {
            palette.add(accentColors.get(index % accentColors.size()));
        }
        return palette;
    }

    private List<Tag> selectTags(List<Tag> commonTags, String categoryName, int index) {
        List<Tag> tags = new ArrayList<>();
        tags.add(commonTags.get(0));
        tags.add(commonTags.get((index % (commonTags.size() - 1)) + 1));
        tags.add(tagRepository.findByName(categoryName.toLowerCase())
                .orElseGet(() -> tagRepository.save(new Tag(categoryName.toLowerCase()))));
        return tags;
    }
}